package quicdissector

import (
	"encoding/hex"
	"testing"
)

func TestSniffQUIC_RealTraffic(t *testing.T) {
	pktHex := []string{
		// pkt-0: QUIC v1 Initial (DCID=12), CRYPTO frame offset 0 + 79-1240 (gap at 69-78).
		"",
		// pkt-1: QUIC v1 Initial (DCID=12), CRYPTO frame offset 69 + 1241-1522 (gap filler + tail).
		"",
		// pkt-2: QUIC v1 Initial (DCID=20 — Retry DCID), fails AEAD, skipped.
		"",
		// pkt-3: QUIC v1 Initial (DCID=20 — Retry DCID), fails AEAD, skipped. Contains second CRYPTO frame.
		"",
	}

	var pkts [][]byte
	for i, h := range pktHex {
		data, err := hex.DecodeString(h)
		if err != nil {
			t.Fatalf("pkt-%d: hex decode error: %v", i, err)
		}
		t.Logf("pkt-%d: len=%d first=0x%02x", i, len(data), data[0])
		pkts = append(pkts, data)
	}

	info, err := SniffQUIC(pkts...)
	if err != nil {
		t.Fatalf("SniffQUIC error: %v", err)
	}

	t.Logf("SNI=%q", info.ServerName)
	if info.ServerName != "cloudflare-quic.com" {
		t.Errorf("ServerName = %q, want %q", info.ServerName, "cloudflare-quic.com")
	}
	if len(info.SupportedProtos) > 0 {
		t.Logf("ALPN=%v", info.SupportedProtos)
	}
}
